const pageMarkdown = $input.first().json.pageMarkdown || '';
const sectionMarkdowns = JSON.parse($input.first().json.sectionMarkdowns || '[]');
const titleOverride = $input.first().json.titleOverride || '';
const labelsStr = $input.first().json.labels || '';

// Combine all markdown
let combinedMd = pageMarkdown;
for (const section of sectionMarkdowns) {
  if (section.trim()) {
    combinedMd += '\n\n---\n\n' + section;
  }
}

// Determine title
let title = titleOverride;
if (!title) {
  const titleMatch = combinedMd.match(/^# (.+)$/m);
  title = titleMatch ? titleMatch[1] : 'Documentation';
}

// Build labels
const labels = ['ai-generated'];
if (labelsStr) labels.push(...labelsStr.split(',').map(l => l.trim()).filter(Boolean));
const labelsJson = labels.map(l => ({ prefix: 'global', name: l }));

// Convert markdown to Confluence storage format HTML
function mdToConfluenceHtml(md) {
  const lines = md.split('\n');
  let html = '';
  let inCodeBlock = false, codeContent = '', codeLang = 'text', inList = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    if (line.startsWith('```') && !inCodeBlock) {
      if (inList) { html += '</ul>'; inList = false; }
      inCodeBlock = true;
      codeLang = line.slice(3).trim() || 'text';
      codeContent = '';
      continue;
    }
    if (line.startsWith('```') && inCodeBlock) {
      inCodeBlock = false;
      html += '<ac:structured-macro ac:name="code"><ac:parameter ac:name="language">' + codeLang + '</ac:parameter><ac:plain-text-body><![CDATA[' + codeContent.trim() + ']]></ac:plain-text-body></ac:structured-macro>';
      continue;
    }
    if (inCodeBlock) { codeContent += line + '\n'; continue; }

    // Tables
    if (line.match(/^\|.+\|$/) && i + 1 < lines.length && lines[i+1].match(/^\|[-| :]+\|$/)) {
      if (inList) { html += '</ul>'; inList = false; }
      const headers = line.split('|').filter(c => c.trim()).map(c => '<th>' + c.trim() + '</th>').join('');
      html += '<table><thead><tr>' + headers + '</tr></thead><tbody>';
      i++;
      while (i + 1 < lines.length && lines[i+1].match(/^\|.+\|$/)) {
        i++;
        const cells = lines[i].split('|').filter(c => c.trim()).map(c => '<td>' + c.trim() + '</td>').join('');
        html += '<tr>' + cells + '</tr>';
      }
      html += '</tbody></table>';
      continue;
    }

    if (line.startsWith('#### ')) { if (inList) { html += '</ul>'; inList = false; } html += '<h4>' + line.slice(5) + '</h4>'; continue; }
    if (line.startsWith('### '))  { if (inList) { html += '</ul>'; inList = false; } html += '<h3>' + line.slice(4) + '</h3>'; continue; }
    if (line.startsWith('## '))   { if (inList) { html += '</ul>'; inList = false; } html += '<h2>' + line.slice(3) + '</h2>'; continue; }
    if (line.startsWith('# '))    { if (inList) { html += '</ul>'; inList = false; } html += '<h1>' + line.slice(2) + '</h1>'; continue; }
    if (line.match(/^---+$/))     { if (inList) { html += '</ul>'; inList = false; } html += '<hr/>'; continue; }
    if (line.startsWith('> '))    { if (inList) { html += '</ul>'; inList = false; } html += '<blockquote><p>' + line.slice(2) + '</p></blockquote>'; continue; }

    if (line.match(/^[-*] /)) {
      if (!inList) { html += '<ul>'; inList = true; }
      let item = line.replace(/^[-*] /, '');
      item = item.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
      item = item.replace(/\*(.+?)\*/g, '<em>$1</em>');
      item = item.replace(/`([^`]+)`/g, '<code>$1</code>');
      html += '<li>' + item + '</li>';
      continue;
    }

    if (line.trim() === '') { if (inList) { html += '</ul>'; inList = false; } continue; }

    if (inList) { html += '</ul>'; inList = false; }
    let p = line;
    p = p.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    p = p.replace(/\*(.+?)\*/g, '<em>$1</em>');
    p = p.replace(/`([^`]+)`/g, '<code>$1</code>');
    p = p.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
    html += '<p>' + p + '</p>';
  }
  if (inList) html += '</ul>';
  return html;
}

let html = mdToConfluenceHtml(combinedMd);
const date = new Date().toISOString().split('T')[0];
html += '<hr/><p><em>Published from markdown by <a href="https://github.com/openmindednewby/ai-confluence-pipeline">ai-confluence-pipeline</a> on ' + date + '</em></p>';

// Build Confluence API body
const confBody = {
  type: 'page',
  title: title,
  space: { key: $env.CONFLUENCE_SPACE_KEY },
  body: { storage: { value: html, representation: 'storage' } },
  metadata: { labels: labelsJson }
};

const parentId = $env.CONFLUENCE_PARENT_PAGE_ID;
if (parentId) confBody.ancestors = [{ id: parentId }];

return [{ json: { confBody, title } }];

const response = $input.first().json;
const title = $('Convert Markdown to Confluence HTML').first().json.title;
const url = (response._links?.base || '') + (response._links?.webui || '');

return [{ json: {
  success: true,
  confluencePage: {
    id: response.id,
    title: title,
    url: url
  }
} }];
